export const getVerraByFamily = (family) => VERRA_PROJECTS.filter(p => p.family === family);
export const getVerraByCluster = (cluster) => VERRA_PROJECTS.filter(p => p.cluster === cluster);
export const getVerraByRegistry = (registry) => VERRA_PROJECTS.filter(p => p.registry === registry);
export const getVerraByCountry = (country) => VERRA_PROJECTS.filter(p => p.country === country);
export const getVerraByRegion = (region) => VERRA_PROJECTS.filter(p => p.region === region);
export const searchVerra = (q) => { const l = q.toLowerCase(); return VERRA_PROJECTS.filter(p => p.name.toLowerCase().includes(l) || p.proponent.toLowerCase().includes(l) || p.country.toLowerCase().includes(l)); };
